def to_float(value):
    if value is None or value == "":
        return None
    if isinstance(value, (int, float)):
        return float(value)
    text = str(value).strip().replace("R$", "").replace("%", "").strip()
    if "," in text and "." in text:
        text = text.replace(".", "").replace(",", ".")
    else:
        text = text.replace(",", ".")
    try:
        return float(text)
    except Exception:
        return None


def normalize_mandato_value(value) -> str:
    if value is None:
        return "BID"

    text = str(value).strip()
    if not text:
        return "BID"

    lowered = (
        text.lower()
        .replace("ã", "a")
        .replace("á", "a")
        .replace("â", "a")
        .replace("é", "e")
        .replace("ê", "e")
        .replace("í", "i")
        .replace("ó", "o")
        .replace("ô", "o")
        .replace("ú", "u")
        .replace("ç", "c")
    )

    if lowered.startswith("sim"):
        return "Sim"
    if lowered.startswith("nao") or lowered.startswith("não"):
        return "Não"
    if "bid" in lowered:
        return "BID"
    return "BID"


def extrair_probabilidade(chance):
    if not chance:
        return 0.0
    t = str(chance).strip().lower()
    if "1" in t and "alta" in t:
        return 0.20
    if "2" in t and ("média" in t or "media" in t):
        return 0.10
    if "3" in t and "baixa" in t:
        return 0.01
    if "alta" in t:
        return 0.20
    if "média" in t or "media" in t:
        return 0.10
    if "baixa" in t:
        return 0.01
    return 0.0


def is_alta_chance(chance):
    if chance is None:
        return False
    t = str(chance).strip().lower()
    return "alta" in t or t.startswith("1")


def extract_folder_id(value: str | None) -> str:
    if not value:
        return ""
    value = str(value).strip()
    match = re.search(r"/folders/([a-zA-Z0-9_-]+)", value)
    if match:
        return match.group(1)
    if re.fullmatch(r"[a-zA-Z0-9_-]{10,}", value):
        return value
    return ""


def infer_sort_key_from_name(path: Path):
    name = path.name.lower()
    date_match = re.search(r"(20\d{2})[^0-9]?(\d{2})[^0-9]?(\d{2})", name)
    if date_match:
        return ("".join(date_match.groups()), name)
    return ("", name)


@st.cache_data(show_spinner=False, ttl=600)
def listar_arquivos_excel(
    folder_url: str = PUBLIC_FOLDER_URL,
    folder_id: str = PUBLIC_FOLDER_ID,
    filename_contains: str = PUBLIC_FILENAME_CONTAINS,
):
    import gdown

    resolved_url = (folder_url or "").strip() or PUBLIC_FOLDER_URL
    resolved_id = extract_folder_id(folder_id) or extract_folder_id(resolved_url) or PUBLIC_FOLDER_ID
    name_filter = normalize_file_match_text(filename_contains or "")

    folder_key = normalize_file_match_text(resolved_id or resolved_url or "default").replace(" ", "_")
    cache_dir = Path(tempfile.gettempdir()) / f"mapa_painel_public_folder_{folder_key}"
    cache_dir.mkdir(parents=True, exist_ok=True)

    downloaded = None
    last_error = None
    attempts = [
        {"id": resolved_id, "url": None},
        {"id": None, "url": resolved_url},
    ]

    for attempt in attempts:
        if not attempt["id"] and not attempt["url"]:
            continue

        kwargs = {
            "quiet": True,
            "use_cookies": False,
        }
        if attempt["id"]:
            kwargs["id"] = attempt["id"]
        if attempt["url"]:
            kwargs["url"] = attempt["url"]

        try:
            try_kwargs = dict(kwargs)
            try_kwargs["output"] = str(cache_dir)
            downloaded = gdown.download_folder(**try_kwargs)
            if downloaded:
                break
        except TypeError as exc:
            last_error = exc
            try:
                downloaded = gdown.download_folder(**kwargs)
                if downloaded:
                    break
            except Exception as exc2:
                last_error = exc2
        except Exception as exc:
            last_error = exc

    if not downloaded:
        detalhe = f" Detalhe: {last_error}" if last_error else ""
        raise FileNotFoundError(
            "Não foi possível listar os arquivos da pasta pública do Google Drive. "
            "Confira se a pasta está em 'Qualquer pessoa com o link'." + detalhe
        )

    candidatos = []
    vistos_candidatos = set()

    for item in downloaded:
        try:
            path = Path(item)
        except Exception:
            continue

        if path.is_file():
            resolved = str(path.resolve())
            if resolved not in vistos_candidatos:
                vistos_candidatos.add(resolved)
                candidatos.append(path)
        elif path.is_dir():
            for child in path.rglob("*"):
                if child.is_file():
                    resolved = str(child.resolve())
                    if resolved not in vistos_candidatos:
                        vistos_candidatos.add(resolved)
                        candidatos.append(child)

    if not candidatos:
        for child in cache_dir.rglob("*"):
            if child.is_file():
                resolved = str(child.resolve())
                if resolved not in vistos_candidatos:
                    vistos_candidatos.add(resolved)
                    candidatos.append(child)

    arquivos = []
    vistos = set()

    for path in candidatos:
        if not path.is_file() or path.suffix.lower() not in EXTENSOES_VALIDAS:
            continue

        normalized_name = normalize_file_match_text(path.name)
        if name_filter and name_filter not in normalized_name:
            continue

        resolved = str(path.resolve())
        if resolved in vistos:
            continue

        vistos.add(resolved)
        arquivos.append(path)

    arquivos.sort(key=infer_sort_key_from_name, reverse=True)
    return arquivos


def listar_arquivos_excel_locais(
    base_dir: Path | None = None,
    filename_contains: str = PUBLIC_FILENAME_CONTAINS,
):
    resolved_base = Path(base_dir) if base_dir else Path(__file__).resolve().parent
    name_filter = normalize_file_match_text(filename_contains or "")

    arquivos = []
    vistos = set()
    for path in resolved_base.rglob("*"):
        try:
            if not path.is_file() or path.suffix.lower() not in EXTENSOES_VALIDAS:
                continue
        except Exception:
            continue
        normalized_name = normalize_file_match_text(path.name)
        if name_filter and name_filter not in normalized_name:
            continue
        resolved = str(path.resolve())
        if resolved in vistos:
            continue
        vistos.add(resolved)
        arquivos.append(path)

    arquivos.sort(key=infer_sort_key_from_name, reverse=True)
    return arquivos


def parse_pipeline_excel_from_bytes(file_bytes: bytes, file_name: str = "upload.xlsx"):
    suffix = Path(file_name).suffix or ".xlsx"
    with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
        tmp.write(file_bytes)
        tmp_path = Path(tmp.name)
    try:
        return parse_pipeline_excel_from_path(tmp_path)
    finally:
        try:
            tmp_path.unlink(missing_ok=True)
        except Exception:
            pass


def parse_pipeline_excel_from_path(file_path: Path):
    wb = load_workbook(filename=str(file_path), data_only=True)
    if "Pipeline" not in wb.sheetnames:
        raise ValueError(f"O arquivo '{file_path.name}' não possui a aba 'Pipeline'.")
    ws = wb["Pipeline"]

    registros = []
    atual = None

    for row in range(1, ws.max_row + 1):
        col_b = ws.cell(row=row, column=2).value
        col_d = ws.cell(row=row, column=4).value
        col_e = ws.cell(row=row, column=5).value
        col_f = ws.cell(row=row, column=6).value

        if col_b == "Cliente:":
            if atual:
                registros.append(atual)

            historico_datas = {}
            for col_idx in range(7, ws.max_column + 1):
                cabecalho_data = ws.cell(row=row, column=col_idx).value
                if cabecalho_data not in [None, ""]:
                    historico_datas[col_idx] = cabecalho_data

            atual = {
                "cliente": col_d,
                "top_five": None,
                "operacao": None,
                "prioridade": None,
                "status": None,
                "responsavel": None,
                "chance_fechamento": None,
                "resumo": None,
                "valor_operacao": None,
                "forma_remuneracao": None,
                "comissao_total": None,
                "comissao_mapa": None,
                "aprovacao_comite": None,
                "mandato": None,
                "status_detalhado": None,
                "atualizacao": None,
                "link_apresentacao": None,
                "link_documentos": None,
                "historicos_disponiveis": [],
                "_historico_datas": historico_datas,
            }
            continue

        if atual is None:
            continue

        if col_b in LABEL_MAP:
            campo = LABEL_MAP[col_b]
            atual[campo] = col_d

            if col_b == "Operação:":
                if col_e not in [None, ""]:
                    atual["status_detalhado"] = col_e
                if col_f not in [None, ""]:
                    atual["atualizacao"] = col_f

                historicos = []
                for col_idx, data_hist in atual.get("_historico_datas", {}).items():
                    comentario = ws.cell(row=row, column=col_idx).value
                    if comentario in [None, ""]:
                        continue
                    historicos.append(
                        {
                            "data": pd.to_datetime(data_hist, errors="coerce"),
                            "comentario": str(comentario).strip(),
                        }
                    )

                historicos.sort(
                    key=lambda item: item["data"] if pd.notna(item["data"]) else pd.Timestamp.min,
                    reverse=True,
                )
                atual["historicos_disponiveis"] = historicos

    if atual:
        registros.append(atual)

    df = pd.DataFrame(registros)
    if not df.empty:
        df = df[
            df[["cliente", "operacao", "status", "responsavel", "valor_operacao"]]
            .notna()
            .any(axis=1)
        ].copy()

    for col in ["valor_operacao", "comissao_total", "comissao_mapa"]:
        if col in df.columns:
            df[col] = df[col].apply(to_float)

    if "top_five" in df.columns:
        df["top_five"] = (
            df["top_five"]
            .astype(str)
            .str.strip()
            .str.lower()
            .map({"sim": "Sim", "não": "Não", "nao": "Não"})
            .fillna(df["top_five"])
        )

    if "mandato" in df.columns:
        df["mandato_filtro"] = df["mandato"].apply(normalize_mandato_value)
    else:
        df["mandato_filtro"] = "BID"

    if "_historico_datas" in df.columns:
        df = df.drop(columns=["_historico_datas"])

    df["prob_fechamento"] = df["chance_fechamento"].apply(extrair_probabilidade)
    df["valor_ponderado"] = df["valor_operacao"].fillna(0) * df["prob_fechamento"]
    df["comissao_mapa"] = df["comissao_mapa"].fillna(0)
    df["comissao_total"] = df["comissao_total"].fillna(0)
    df["comissao_mapa_ponderada"] = df["comissao_mapa"] * df["prob_fechamento"]
    df["valor_operacao"] = df["valor_operacao"].fillna(0)
    return df


def format_brl(valor):
    try:
        return f"R$ {valor:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
    except Exception:
        return "R$ 0,00"


def format_brl_card(valor):
    try:
        valor = 0 if valor is None else round(float(valor))
        return f"R$ {valor:,.0f}".replace(",", "X").replace(".", ",").replace("X", ".")
    except Exception:
        return "R$ 0"


def nl2br(text):
    if text is None:
        return "—"
    txt = escape(str(text).strip())
    return txt.replace("\n", "<br>") if txt else "—"


def val(text):
    if text is None:
        return "—"
    text = str(text).strip()
    return escape(text) if text else "—"


def format_history_date(value):
    data = pd.to_datetime(value, errors="coerce")
    if pd.notna(data):
        return data.strftime("%d/%m/%Y")
    txt = str(value).strip() if value is not None else ""
    return escape(txt) if txt else "Sem data"


def build_history_cards_html(historicos):
    if historicos is None:
        return "—"

    if isinstance(historicos, float) and pd.isna(historicos):
        return "—"

    if not isinstance(historicos, list):
        texto = str(historicos).strip()
        return nl2br(texto) if texto else "—"

    if not historicos:
        return "—"

    cards = ['<div class="history-list">']
    for idx, item in enumerate(historicos):
        data_txt = format_history_date(item.get("data"))
        comentario = nl2br(item.get("comentario"))
        open_attr = " open" if idx == 0 else ""
        cards.append(
            f"""
            <details class="history-item"{open_attr}>
                <summary>{data_txt}</summary>
                <div class="history-body">{comentario}</div>
            </details>
            """
        )
    cards.append("</div>")
    return "".join(cards)


def build_operation_color_sequence(operation_names):
    sequence = []
    fallback_idx = 0
    for raw_name in operation_names:
        name = "" if pd.isna(raw_name) else str(raw_name).strip()
        if name in OPERATION_COLOR_MAP:
            sequence.append(OPERATION_COLOR_MAP[name])
        else:
            sequence.append(OPERATION_FALLBACK_COLORS[fallback_idx % len(OPERATION_FALLBACK_COLORS)])
            fallback_idx += 1
    return sequence


def metric_card(label, value, sub=None):
    sub_html = f'<div class="metric-sub">{escape(str(sub))}</div>' if sub else ''
    return f"""
    <div class="metric-card">
        <div class="metric-label">{escape(label)}</div>
        <div class="metric-value">{escape(value)}</div>
        {sub_html}
    </div>
    """


