def apply_multiselect_filter(series: pd.Series, selected_values: list[str]):
    if not selected_values:
        return pd.Series([True] * len(series), index=series.index)
    normalized = series.fillna("").astype(str).str.strip()
    return normalized.isin(selected_values)


def make_options(series):
    return sorted([str(x).strip() for x in series.dropna().unique().tolist() if str(x).strip()])


